import { useNavigate } from 'react-router-dom';
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import {
  Container,
  Typography,
  Grid,
  Paper,
  TextField,
  MenuItem
} from '@mui/material';

function Dashboard() {
  const [data, setData] = useState([]);
  const [filters, setFilters] = useState({});

  const loadData = () => {
    axios.get('http://localhost:3001/complaints', {
      params: filters
    })
      .then(res => setData(res.data))
      .catch(err => console.error(err));
  };

  useEffect(() => {
    loadData();
  }, [filters]);

  // 📊 MÉTRICAS
  const total = data.length;
  const abertas = data.filter(d => d.status === 'aberta').length;
  const alta = data.filter(d => d.criticality === 'alta').length;

  return (
    <Container>
      <Typography variant="h4" mt={3} mb={2}>
        Dashboard de Reclamações
      </Typography>

      {/* 🔍 FILTROS */}
      <Grid container spacing={2}>
        <Grid item xs={3}>
          <TextField
            select
            label="Criticidade"
            fullWidth
            onChange={(e) => setFilters({ ...filters, criticality: e.target.value })}
          >
            <MenuItem value="">Todos</MenuItem>
            <MenuItem value="baixa">Baixa</MenuItem>
            <MenuItem value="media">Média</MenuItem>
            <MenuItem value="alta">Alta</MenuItem>
          </TextField>
        </Grid>

        <Grid item xs={3}>
          <TextField
            select
            label="Status"
            fullWidth
            onChange={(e) => setFilters({ ...filters, status: e.target.value })}
          >
            <MenuItem value="">Todos</MenuItem>
            <MenuItem value="aberta">Aberta</MenuItem>
            <MenuItem value="resolvida">Resolvida</MenuItem>
          </TextField>
        </Grid>
      </Grid>

      {/* 📊 CARDS */}
      <Grid container spacing={2} mt={2}>
        <Grid item xs={4}>
          <Paper sx={{ p: 2 }}>
            <Typography>Total</Typography>
            <Typography variant="h5">{total}</Typography>
          </Paper>
        </Grid>

        <Grid item xs={4}>
          <Paper sx={{ p: 2 }}>
            <Typography>Abertas</Typography>
            <Typography variant="h5">{abertas}</Typography>
          </Paper>
        </Grid>

        <Grid item xs={4}>
          <Paper sx={{ p: 2 }}>
            <Typography>Alta Criticidade</Typography>
            <Typography variant="h5">{alta}</Typography>
          </Paper>
        </Grid>
      </Grid>

      {/* 📋 TABELA */}
      <Paper sx={{ mt: 3, p: 2 }}>
        <table width="100%">
          <thead>
            <tr>
              <th>Clínica</th>
              <th>Paciente</th>
              <th>Descrição</th>
              <th>Criticidade</th>
              <th>Status</th>
              <th>Prazo</th>
            </tr>
          </thead>

          <tbody>
            {data.map((row) => (
              <tr key={row.id}>
                <td>{row.clinic_name}</td>
                <td>{row.patient_name}</td>
                <td>{row.description}</td>
                <td>{row.criticality}</td>
                <td>{row.status}</td>
                <td>{row.due_date}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </Paper>

    </Container>
  );
}

export default Dashboard;
const navigate = useNavigate();

useEffect(() => {
  const token = localStorage.getItem('token');

  if (!token) {
    navigate('/login');
  }
}, []);
